// area.ts
function area(s: Shape) {
  switch (s.kind) { case 'circle': return Math.PI * s.r * s.r; case 'square': return s.side * s.side; }
}
// perimeter.ts
function perimeter(s: Shape) {
  switch (s.kind) { case 'circle': return 2 * Math.PI * s.r; case 'square': return 4 * s.side; }
}
// label.ts
function label(s: Shape) {
  switch (s.kind) { case 'circle': return 'circle'; case 'square': return 'square'; }
}

