class CachedUserRepo {
  private cache = new Map<string, User>();
  constructor(private inner: UserRepo) {}
  find(id: string) {
    if (!this.cache.has(id)) this.cache.set(id, this.inner.find(id));
    return this.cache.get(id);
  }
}

