class Money:
    def __init__(self, cents, currency):
        self.cents = cents
        self.currency = currency
    def add(self, other):
        return Money(self.cents + other.cents, self.currency)
    def subtract(self, other):
        return Money(self.cents - other.cents, self.currency)
    def format(self):
        return f"{self.cents / 100:.2f} {self.currency}"
